import{_ as a,o as t,c as i,ag as n}from"./chunks/framework.CvgP6Fyv.js";const b=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"nl/features/dashboard.md","filePath":"nl/features/dashboard.md"}'),r={name:"nl/features/dashboard.md"};function o(l,e,d,s,h,c){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h1><p>Het dashboard is je startpagina in MyCompanyDesk. Het geeft je in een oogopslag een overzicht van je bedrijfsfinancien, meldingen en snelle acties.</p><h2 id="dashboardprofielen" tabindex="-1">Dashboardprofielen <a class="header-anchor" href="#dashboardprofielen" aria-label="Permalink to &quot;Dashboardprofielen&quot;">​</a></h2><p>MyCompanyDesk biedt rolgebaseerde dashboardprofielen die de getoonde statistieken en kaarten afstemmen op jouw behoeften:</p><table tabindex="0"><thead><tr><th>Profiel</th><th>Focus</th></tr></thead><tbody><tr><td><strong>Eigenaar / Directeur</strong></td><td>Cashflow, winstgevendheid, overzicht op hoog niveau</td></tr><tr><td><strong>Boekhouder / Accountant</strong></td><td>BTW, compliance, audittrails, periodeversluitingen</td></tr><tr><td><strong>Debiteuren (Facturatie)</strong></td><td>Factuurstatistieken, openstaande betalingen</td></tr><tr><td><strong>Crediteuren (Inkoop)</strong></td><td>Uitgaven bijhouden, leveranciersbeheer</td></tr><tr><td><strong>Freelancer</strong></td><td>Vereenvoudigd facturatie- en inkomstenoverzicht</td></tr><tr><td><strong>BTW-compliance</strong></td><td>BTW-berekeningen, deadlines, aangiftes</td></tr><tr><td><strong>Projectgericht</strong></td><td>Projectwinstgevendheid, tijdregistratie</td></tr><tr><td><strong>Groei / Operations</strong></td><td>Omzettrends, klantenwerving</td></tr></tbody></table><h3 id="profiel-wijzigen" tabindex="-1">Profiel wijzigen <a class="header-anchor" href="#profiel-wijzigen" aria-label="Permalink to &quot;Profiel wijzigen&quot;">​</a></h3><ol><li>Open het dashboard</li><li>Klik op de profielkiezer bovenaan</li><li>Kies het profiel dat het beste bij je rol past</li></ol><p>Elk profiel toont andere statistiekkaarten, meldingen en snelle acties die relevant zijn voor die rol.</p><h2 id="dashboardonderdelen" tabindex="-1">Dashboardonderdelen <a class="header-anchor" href="#dashboardonderdelen" aria-label="Permalink to &quot;Dashboardonderdelen&quot;">​</a></h2><h3 id="meldingen" tabindex="-1">Meldingen <a class="header-anchor" href="#meldingen" aria-label="Permalink to &quot;Meldingen&quot;">​</a></h3><p>Kritieke zaken die je aandacht vereisen:</p><ul><li>Achterstallige facturen</li><li>Aankomende BTW-deadlines</li><li>Aflopende contracten</li><li>Waarschuwingen bij lage cashflow</li></ul><h3 id="belangrijke-statistieken" tabindex="-1">Belangrijke statistieken <a class="header-anchor" href="#belangrijke-statistieken" aria-label="Permalink to &quot;Belangrijke statistieken&quot;">​</a></h3><p>Samenvattingskaarten met je belangrijkste cijfers:</p><ul><li>Totale omzet (huidige periode)</li><li>Openstaande facturen</li><li>Totale uitgaven</li><li>Nettowinst/-verlies</li><li>Open offertes</li></ul><h3 id="periodeselectie" tabindex="-1">Periodeselectie <a class="header-anchor" href="#periodeselectie" aria-label="Permalink to &quot;Periodeselectie&quot;">​</a></h3><p>Wissel tussen verschillende tijdsperioden om je statistieken te bekijken:</p><ul><li>Deze week / maand / kwartaal / jaar</li><li>Aangepast datumbereik</li><li>Vergelijken met voorgaande perioden</li></ul><h3 id="snelle-acties" tabindex="-1">Snelle acties <a class="header-anchor" href="#snelle-acties" aria-label="Permalink to &quot;Snelle acties&quot;">​</a></h3><p>Snelkoppelingen naar je meest voorkomende taken:</p><ul><li>Nieuwe factuur aanmaken</li><li>Uitgave toevoegen</li><li>Tijdregistratie invoeren</li><li>Rapportages bekijken</li></ul><h3 id="recente-activiteit" tabindex="-1">Recente activiteit <a class="header-anchor" href="#recente-activiteit" aria-label="Permalink to &quot;Recente activiteit&quot;">​</a></h3><p>Een feed van recente gebeurtenissen in je werkruimte:</p><ul><li>Verzonden en betaalde facturen</li><li>Toegevoegde uitgaven</li><li>Aangemaakte klanten</li><li>Acties van teamleden</li></ul><h2 id="onboardingkaart" tabindex="-1">Onboardingkaart <a class="header-anchor" href="#onboardingkaart" aria-label="Permalink to &quot;Onboardingkaart&quot;">​</a></h2><p>Nieuwe gebruikers zien een onboardingkaart die hen door de eerste installatie begeleidt:</p><ol><li>Bedrijfsinformatie instellen</li><li>Eerste klant toevoegen</li><li>Eerste factuur aanmaken</li></ol><p>De kaart houdt je voortgang bij en verdwijnt zodra alles is voltooid (of wanneer je hem handmatig sluit).</p>',28)])])}const u=a(r,[["render",o]]);export{b as __pageData,u as default};
